@st.cache_resource
def init_supabase() -> Client:
    return create_client(st.secrets["SUPABASE_URL"], st.secrets["SUPABASE_KEY"])

supabase = init_supabase()

# ── JS: Streamlit-Badge via DOM entfernen (CSS allein nicht zuverlässig) ──
components.html("""
<script>
(function() {
    function removeBadge() {
        var doc = window.parent.document;
        var selectors = [
            '[data-testid="stStatusWidget"]',
            '[data-testid="stToolbar"]',
            '[class*="StatusWidget"]',
            '[class*="toolbarActions"]',
            '[class*="stBottom"]',
            '.st-emotion-cache-zq5wmm',
            '.st-emotion-cache-1dp5vir',
            '.st-emotion-cache-h5rgaw'
        ];
        selectors.forEach(function(sel) {
            doc.querySelectorAll(sel).forEach(function(el) {
                el.style.setProperty('display', 'none', 'important');
            });
        });
        // Generisch: fixed-positionierte Elemente in bottom-right Ecke
        doc.querySelectorAll('body > div, .stApp > div').forEach(function(el) {
            var s = window.getComputedStyle(el);
            if (s.position === 'fixed' && parseInt(s.bottom) < 100 &&
                parseInt(s.right) < 100 && el.offsetWidth < 300) {
                // nur kleine Elemente unten rechts (= Badge), nicht Nav-Bar
                if (el.offsetWidth < 200 && el.offsetHeight < 80) {
                    el.style.setProperty('display', 'none', 'important');
                }
            }
        });
    }
    // Mehrfach versuchen, da Streamlit asynchron rendert
    [300, 800, 1500, 3000].forEach(function(ms) {
        setTimeout(removeBadge, ms);
    });
})();
</script>
""", height=0)

