# BOTTOM NAVIGATION — reines HTML, kein Streamlit-Button-Trick
# Icons direkt als <img> eingebettet, Links via ?page= Query-Param
# ─────────────────────────────────────────────
def bottom_nav():
    tab = st.session_state.active_tab
    p_icon = ICON_PROFIL_AKTIV if tab == "profil"      else ICON_PROFIL_PASSIV
    s_icon = ICON_SCAN_AKTIV   if tab == "scan"        else ICON_SCAN_PASSIV
    r_icon = ICON_REST_AKTIV   if tab == "restaurants" else ICON_REST_PASSIV

    # FIX: target="_self" verhindert, dass Links in neuem Tab öffnen
    st.markdown(f"""
    <div class="nc-bottom-nav">
        <a href="?page=profil_uebersicht" target="_self">
            <img src="data:image/png;base64,{p_icon}" />
        </a>
        <a href="?page=scan" target="_self">
            <img src="data:image/png;base64,{s_icon}" />
        </a>
        <a href="?page=restaurants" target="_self">
            <img src="data:image/png;base64,{r_icon}" />
        </a>
    </div>
    """, unsafe_allow_html=True)

